namespace sv_d266e46d555744c7b80a68fbf73fe7ca.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@namespace sv_d266e46d555744c7b80a68fbf73fe7ca.Components.Chat

<div class="message-input">
    <textarea @bind="text" @bind:event="oninput"
              @onkeydown="HandleKeyDown"
              placeholder="@Placeholder"
              rows="2"></textarea>
    <button class="btn btn-primary btn-sm" @onclick="Send" disabled="@string.IsNullOrWhiteSpace(text)">
        @ButtonLabel
    </button>
</div>

@code {
    private string text = string.Empty;

    [Parameter] public string Placeholder { get; set; } = "Type a message…";
    [Parameter] public string ButtonLabel { get; set; } = "Send";
    [Parameter] public EventCallback<string> OnSend { get; set; }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await Send();
        }
    }

    private async Task Send()
    {
        if (string.IsNullOrWhiteSpace(text)) return;
        var content = text.Trim();
        text = string.Empty;
        await OnSend.InvokeAsync(content);
    }
}

@namespace sv_d266e46d555744c7b80a68fbf73fe7ca.Components.Chat

<div class="emoji-picker">
    @foreach (var emoji in Emojis)
    {
        <button class="emoji-btn" @onclick="() => OnEmojiSelected.InvokeAsync(emoji)"
                title="@emoji">@emoji</button>
    }
</div>

@code {
    private static readonly string[] Emojis = ["👍", "❤️", "😂", "🎉", "😮", "😢"];

    [Parameter] public EventCallback<string> OnEmojiSelected { get; set; }
}

@namespace sv_d266e46d555744c7b80a68fbf73fe7ca.Components.Chat
@using sv_d266e46d555744c7b80a68fbf73fe7ca.Services

<div class="message-bubble @(IsThreadRoot ? "thread-root" : "")"
     @onmouseenter="() => showActions = true"
     @onmouseleave="() => { showActions = false; showEmojiPicker = false; }">
    <div class="message-header">
        <strong class="message-author">@Message.Author</strong>
        <span class="message-time" title="@Message.SentAt.ToString("f")">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="message-reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <span class="reaction-badge" title="@string.Join(", ", reaction.Users)">
                    @reaction.Emoji @reaction.Users.Count
                </span>
            }
        </div>
    }

    @if (IsThreadRoot && ReplyCount > 0)
    {
        <button class="thread-link" @onclick="() => OnReplyClicked.InvokeAsync(Message.Id)">
            @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (showActions)
    {
        <div class="message-actions">
            <button class="action-btn" @onclick="() => OnReplyClicked.InvokeAsync(Message.Id)" title="Reply">
                💬
            </button>
            <button class="action-btn" @onclick="ToggleEmojiPicker" title="React">
                😊
            </button>
        </div>
        @if (showEmojiPicker)
        {
            <EmojiPicker OnEmojiSelected="HandleReaction" />
        }
    }
</div>

@code {
    private bool showActions;
    private bool showEmojiPicker;

    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public bool IsThreadRoot { get; set; }
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public EventCallback<int> OnReplyClicked { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReactionAdded { get; set; }

    private void ToggleEmojiPicker() => showEmojiPicker = !showEmojiPicker;

    private async Task HandleReaction(string emoji)
    {
        showEmojiPicker = false;
        await OnReactionAdded.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d");
    }
}

@namespace sv_d266e46d555744c7b80a68fbf73fe7ca.Components.Chat
@using sv_d266e46d555744c7b80a68fbf73fe7ca.Services

<div class="channel-item @(IsActive ? "active" : "")" @onclick="() => OnSelected.InvokeAsync(Channel.Id)">
    <div class="channel-name"># @Channel.Name</div>
    <div class="channel-desc">@TruncateDescription(Channel.Description)</div>
    @if (Channel.UnreadCount > 0)
    {
        <span class="unread-badge">@Channel.UnreadCount</span>
    }
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback<int> OnSelected { get; set; }

    private static string TruncateDescription(string desc)
        => desc.Length > 40 ? desc[..37] + "…" : desc;
}

@namespace sv_d266e46d555744c7b80a68fbf73fe7ca.Components.Chat
@using sv_d266e46d555744c7b80a68fbf73fe7ca.Services

<div class="channel-sidebar">
    <h5 class="sidebar-title">Channels</h5>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == SelectedChannelId"
                         OnSelected="OnChannelSelected" />
        }
    </div>
</div>

@code {
    [Parameter] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int SelectedChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

@namespace sv_d266e46d555744c7b80a68fbf73fe7ca.Components.Chat
@using sv_d266e46d555744c7b80a68fbf73fe7ca.Services

<div class="thread-panel">
    <div class="thread-header">
        <h6>Thread</h6>
        <button class="btn-close" @onclick="OnClose" aria-label="Close thread"></button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-quote">
            <strong>@RootMessage.Author</strong>
            <p>@RootMessage.Content</p>
        </div>
    }

    <div class="thread-messages">
        @foreach (var msg in Replies)
        {
            <MessageBubble Message="msg" OnReactionAdded="OnReactionAdded" />
        }
    </div>

    <MessageInput Placeholder="Reply in thread…"
                  ButtonLabel="Reply"
                  OnSend="OnSendReply" />
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReactionAdded { get; set; }
}

