@page "/chat"
@namespace sv_d266e46d555744c7b80a68fbf73fe7ca.Components.Pages
@rendermode InteractiveServer
@using sv_d266e46d555744c7b80a68fbf73fe7ca.Components.Chat
@using sv_d266e46d555744c7b80a68fbf73fe7ca.Services
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <ChannelSidebar Channels="channels"
                    SelectedChannelId="selectedChannelId"
                    OnChannelSelected="SelectChannel" />

    <div class="message-area @(threadOpen ? "with-thread" : "")">
        @if (selectedChannel is not null)
        {
            <div class="area-header">
                <h5># @selectedChannel.Name</h5>
                <span class="area-desc">@selectedChannel.Description</span>
            </div>

            <div class="message-list" @onscroll="HandleScroll">
                @if (loadingMore)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @foreach (var msg in messages)
                {
                    var summary = threadSummaries.GetValueOrDefault(msg.Id);
                    <MessageBubble Message="msg"
                                   IsThreadRoot="@(summary is not null || messages.Any(m => m.ReplyToId == msg.Id))"
                                   ReplyCount="@(summary?.ReplyCount ?? 0)"
                                   OnReplyClicked="OpenThread"
                                   OnReactionAdded="HandleReaction" />
                }
            </div>

            <MessageInput Placeholder="Message #@selectedChannel.Name"
                          OnSend="SendMessage" />
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (threadOpen && threadRootMessage is not null)
    {
        <ThreadPanel RootMessage="threadRootMessage"
                     Replies="threadReplies"
                     OnClose="CloseThread"
                     OnSendReply="SendThreadReply"
                     OnReactionAdded="HandleReaction" />
    }
</div>

@code {
    private List<Channel> channels = [];
    private List<Message> messages = [];
    private List<Message> threadReplies = [];
    private Dictionary<int, ThreadSummary> threadSummaries = new();
    private Channel? selectedChannel;
    private int selectedChannelId;
    private bool threadOpen;
    private Message? threadRootMessage;
    private bool loadingMore;
    private bool allMessagesLoaded;
    private const int PageSize = 30;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        selectedChannelId = channelId;
        selectedChannel = channels.FirstOrDefault(c => c.Id == channelId);
        allMessagesLoaded = false;
        messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        BuildThreadSummaries();
        CloseThread();
        await ChatService.MarkChannelReadAsync(channelId);

        // Update local unread count
        var idx = channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            channels[idx] = channels[idx] with { UnreadCount = 0 };
        }
    }

    private async Task HandleScroll()
    {
        // Triggered on scroll — load more when user scrolls to top
        if (loadingMore || allMessagesLoaded) return;

        loadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(selectedChannelId, messages.Count, PageSize);
        if (older.Count < PageSize)
        {
            allMessagesLoaded = true;
        }

        messages.InsertRange(0, older);
        BuildThreadSummaries();
        loadingMore = false;
    }

    private async Task SendMessage(string content)
    {
        var msg = await ChatService.SendMessageAsync(selectedChannelId, content, null);
        messages.Add(msg);
    }

    private async Task OpenThread(int messageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == messageId);
        if (threadRootMessage is null) return;

        threadReplies = await ChatService.GetThreadAsync(messageId);
        threadOpen = true;
    }

    private void CloseThread()
    {
        threadOpen = false;
        threadRootMessage = null;
        threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (threadRootMessage is null) return;

        var reply = await ChatService.SendMessageAsync(selectedChannelId, content, threadRootMessage.Id);
        threadReplies.Add(reply);

        // Update thread summary
        threadSummaries[threadRootMessage.Id] = new ThreadSummary(
            threadRootMessage.Id,
            threadReplies.Count,
            reply.SentAt);
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistically update the message in local state
        UpdateReactionInList(messages, args.MessageId, args.Emoji);
        UpdateReactionInList(threadReplies, args.MessageId, args.Emoji);
    }

    private static void UpdateReactionInList(List<Message> list, int messageId, string emoji)
    {
        var idx = list.FindIndex(m => m.Id == messageId);
        if (idx < 0) return;

        var msg = list[idx];
        var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == emoji);
        if (existing is not null)
        {
            if (!existing.Users.Contains("You"))
                existing.Users.Add("You");
        }
        else
        {
            msg.Reactions.Add(new Reaction(emoji, ["You"]));
        }
    }

    private void BuildThreadSummaries()
    {
        threadSummaries.Clear();
        var replies = messages.Where(m => m.ReplyToId.HasValue).GroupBy(m => m.ReplyToId!.Value);
        foreach (var group in replies)
        {
            threadSummaries[group.Key] = new ThreadSummary(
                group.Key,
                group.Count(),
                group.Max(m => m.SentAt));
        }
    }
}

/* ── Chat Layout ── */
.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
}

/* ── Channel Sidebar ── */
::deep .channel-sidebar {
    width: 20%;
    min-width: 200px;
    background: #2c2f33;
    color: #dcddde;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #202225;
}

::deep .sidebar-title {
    padding: 16px;
    margin: 0;
    font-size: 0.85rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: #8e9297;
    border-bottom: 1px solid #202225;
}

::deep .channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

::deep .channel-item {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    padding: 8px 16px;
    cursor: pointer;
    transition: background 0.15s;
    position: relative;
}

::deep .channel-item:hover {
    background: #34373c;
}

::deep .channel-item.active {
    background: #393c43;
    color: #fff;
}

::deep .channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    flex: 1;
}

::deep .channel-desc {
    width: 100%;
    font-size: 0.75rem;
    color: #72767d;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

::deep .unread-badge {
    background: #ed4245;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    border-radius: 10px;
    padding: 1px 6px;
    min-width: 18px;
    text-align: center;
}

/* ── Message Area ── */
.message-area {
    flex: 1;
    display: flex;
    flex-direction: column;
    background: #36393f;
    color: #dcddde;
    min-width: 0;
}

.message-area.with-thread {
    flex: 0 0 55%;
}

.area-header {
    padding: 12px 20px;
    border-bottom: 1px solid #202225;
    background: #36393f;
}

.area-header h5 {
    margin: 0;
    color: #fff;
    font-size: 1.1rem;
}

.area-desc {
    font-size: 0.8rem;
    color: #8e9297;
}

.no-channel-selected {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #72767d;
    font-size: 1.1rem;
}

/* ── Message List ── */
.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 16px 20px;
    display: flex;
    flex-direction: column;
    gap: 4px;
}

.loading-indicator {
    text-align: center;
    color: #72767d;
    padding: 8px;
    font-size: 0.85rem;
}

/* ── Message Bubble ── */
::deep .message-bubble {
    padding: 6px 12px;
    border-radius: 4px;
    position: relative;
    transition: background 0.1s;
}

::deep .message-bubble:hover {
    background: #32353b;
}

::deep .message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
}

::deep .message-author {
    color: #fff;
    font-size: 0.95rem;
}

::deep .message-time {
    color: #72767d;
    font-size: 0.72rem;
}

::deep .message-content {
    margin-top: 2px;
    line-height: 1.4;
    word-break: break-word;
}

/* ── Reactions ── */
::deep .message-reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

::deep .reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    background: #2f3136;
    border: 1px solid #40444b;
    border-radius: 4px;
    padding: 2px 6px;
    font-size: 0.8rem;
    cursor: default;
}

/* ── Thread Link ── */
::deep .thread-link {
    background: none;
    border: none;
    color: #00aff4;
    font-size: 0.8rem;
    cursor: pointer;
    padding: 2px 0;
    margin-top: 2px;
}

::deep .thread-link:hover {
    text-decoration: underline;
}

/* ── Message Actions ── */
::deep .message-actions {
    position: absolute;
    top: -8px;
    right: 8px;
    display: flex;
    gap: 2px;
    background: #2f3136;
    border: 1px solid #40444b;
    border-radius: 4px;
    padding: 2px;
    z-index: 10;
}

::deep .action-btn {
    background: none;
    border: none;
    cursor: pointer;
    padding: 4px 6px;
    font-size: 1rem;
    border-radius: 3px;
    line-height: 1;
}

::deep .action-btn:hover {
    background: #40444b;
}

/* ── Emoji Picker ── */
::deep .emoji-picker {
    position: absolute;
    top: -8px;
    right: 70px;
    display: flex;
    gap: 2px;
    background: #2f3136;
    border: 1px solid #40444b;
    border-radius: 4px;
    padding: 4px;
    z-index: 20;
}

::deep .emoji-btn {
    background: none;
    border: none;
    cursor: pointer;
    padding: 4px;
    font-size: 1.2rem;
    border-radius: 3px;
    line-height: 1;
}

::deep .emoji-btn:hover {
    background: #40444b;
}

/* ── Message Input ── */
::deep .message-input {
    display: flex;
    gap: 8px;
    padding: 12px 20px;
    border-top: 1px solid #202225;
    background: #36393f;
}

::deep .message-input textarea {
    flex: 1;
    resize: none;
    background: #40444b;
    border: none;
    border-radius: 6px;
    color: #dcddde;
    padding: 10px 14px;
    font-size: 0.9rem;
    font-family: inherit;
    outline: none;
}

::deep .message-input textarea::placeholder {
    color: #72767d;
}

::deep .message-input .btn {
    align-self: flex-end;
}

/* ── Thread Panel ── */
::deep .thread-panel {
    width: 25%;
    min-width: 280px;
    background: #2f3136;
    color: #dcddde;
    display: flex;
    flex-direction: column;
    border-left: 1px solid #202225;
}

::deep .thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid #202225;
}

::deep .thread-header h6 {
    margin: 0;
    color: #fff;
    font-size: 1rem;
    font-weight: 700;
}

::deep .thread-header .btn-close {
