toolArgs.file_text:
/* ── Chat Layout ── */
.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
}

/* ── Channel Sidebar ── */
::deep .channel-sidebar {
    width: 20%;
    min-width: 200px;
    background: #2c2f33;
    color: #dcddde;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #202225;
}

::deep .sidebar-title {
    padding: 16px;
    margin: 0;
    font-size: 0.85rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: #8e9297;
    border-bottom: 1px solid #202225;
}

::deep .channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

::deep .channel-item {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    padding: 8px 16px;
    cursor: pointer;
    transition: background 0.15s;
    position: relative;
}

::deep .channel-item:hover {
    background: #34373c;
}

::deep .channel-item.active {
    background: #393c43;
    color: #fff;
}

::deep .channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    flex: 1;
}

::deep .channel-desc {
    width: 100%;
    font-size: 0.75rem;
    color: #72767d;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

::deep .unread-badge {
    background: #ed4245;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    border-radius: 10px;
    padding: 1px 6px;
    min-width: 18px;
    text-align: center;
}

/* ── Message Area ── */
.message-area {
    flex: 1;
    display: flex;
    flex-direction: column;
    background: #36393f;
    color: #dcddde;
    min-width: 0;
}

.message-area.with-thread {
    flex: 0 0 55%;
}

.area-header {
    padding: 12px 20px;
